page_errors.error:
Command '['node', '-e', "
const { chromium } = require('playwright');

(async() => {

  const browser = await chromium.launch({ headless: true });

  // Desktop screenshot
  const desktopPage = await browser.newPage({
    viewport: { width: 1440, height: 2200 }
  });

  await desktopPage.goto('https://openai.com', { waitUntil: 'networkidle', timeout: 30000 });

  await desktopPage.screenshot({
    path: 'reports/openai/raw/screenshots/home_desktop.png',
    fullPage: true
  });

  // Mobile screenshot
  const mobilePage = await browser.newPage({
    viewport: { width: 390, height: 844 },
    userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 15_0 like Mac OS X)'
  });

  await mobilePage.goto('https://openai.com', { waitUntil: 'networkidle', timeout: 30000 });

  await mobilePage.screenshot({
    path: 'reports/openai/raw/screenshots/home_mobile.png',
    fullPage: true
  });

  await browser.close();

})();
"]' returned non-zero exit status 1.

